/*
  Antares Construction & Engineering
  Global layout & design system
====================================== */

:root {
  /* Color system */
  --color-primary-red: #D8262F;
  --color-primary-black: #111111;

  --color-secondary-light: #F2F2F2;
  --color-secondary-dark: #2B2B2B;

  --color-neutral-white: #FFFFFF;
  --color-neutral-gray: #CCCCCC;

  --color-border-subtle: #E0E0E0;

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;

  --fs-h1: 32px;
  --fs-h2: 24px;
  --fs-h3: 20px;
  --fs-body: 14px;
  --fs-small: 12px;

  --fw-light: 300;
  --fw-regular: 400;
  --fw-medium: 500;
  --fw-semibold: 600;
  --fw-bold: 700;

  --lh-tight: 1.2;
  --lh-normal: 1.5;
  --lh-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Layout */
  --layout-max-width: 1200px;
  --header-utility-height: 40px;
}

/* Global reset & base styles -------------------------- */

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--fs-body);
  line-height: var(--lh-normal);
  color: var(--color-primary-black);
  background-color: var(--color-neutral-white);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

.page {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.container {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-3);
}

.site-main {
  flex: 1 0 auto;
  padding: var(--space-4) 0 var(--space-5);
}

/* Utility bar ---------------------------------------- */

.utility-bar {
  background-color: var(--color-secondary-light);
  border-bottom: 1px solid var(--color-border-subtle);
  height: var(--header-utility-height);
  display: flex;
  align-items: center;
}

.utility-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.utility-left {
  display: flex;
  align-items: center;
  gap: 0;
}

.utility-right {
  display: flex;
  align-items: center;
  gap: var(--space-1);
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0 var(--space-2);
  height: 32px;
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: var(--fw-semibold);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  border: none;
  cursor: pointer;
}

.btn-utility {
  background-color: var(--color-primary-red);
  color: var(--color-neutral-white);
  border-radius: 0;
  border-right: 1px solid rgba(0, 0, 0, 0.08);
}

.btn-utility:first-child {
  border-left: 1px solid rgba(0, 0, 0, 0.08);
}

.btn-utility:hover,
.btn-utility:focus {
  background-color: #b01d25;
  text-decoration: none;
}

.btn-icon {
  width: 18px;
  height: 18px;
  margin-right: var(--space-1);
  position: relative;
}

/* Simple geometric pseudo-icons to echo mail/calculator */

.btn-icon-mail::before,
.btn-icon-mail::after,
.btn-icon-calc::before,
.btn-icon-calc::after {
  content: "";
  position: absolute;
  background-color: var(--color-neutral-white);
}

/* Envelope icon */
.btn-icon-mail::before {
  inset: 3px 2px 3px 2px;
  border-radius: 2px;
}

.btn-icon-mail::after {
  left: 3px;
  right: 3px;
  top: 6px;
  height: 2px;
  transform: skewY(-20deg);
}

/* Calculator icon */
.btn-icon-calc::before {
  inset: 3px 3px 3px 3px;
  border-radius: 2px;
}

.btn-icon-calc::after {
  width: 10px;
  height: 2px;
  left: 4px;
  top: 5px;
}

.btn-label {
  white-space: nowrap;
}

/* Brand bar ------------------------------------------ */

.brand-bar {
  background-color: var(--color-primary-black);
  color: var(--color-neutral-white);
}

.brand-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-3);
  padding-bottom: var(--space-3);
}

.brand-left {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.logo-mark {
  width: 48px;
  height: 48px;
  background: linear-gradient(135deg, var(--color-primary-red), #8f141a);
  position: relative;
}

/* Feather-like vertical accents */
.logo-mark::before,
.logo-mark::after {
  content: "";
  position: absolute;
  top: 8px;
  bottom: 8px;
  width: 6px;
  border-radius: 12px;
  background-color: var(--color-neutral-white);
}

.logo-mark::before {
  left: 12px;
}

.logo-mark::after {
  right: 12px;
}

.logo-text {
  display: flex;
  flex-direction: column;
}

.logo-name {
  font-family: var(--font-heading);
  font-size: 28px;
  font-weight: var(--fw-medium);
  letter-spacing: 0.35em;
  line-height: var(--lh-tight);
}

.logo-tagline {
  margin-top: 4px;
  font-size: 12px;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  opacity: 0.75;
}

.brand-right {
  display: flex;
  align-items: center;
  gap: var(--space-3);
}

.header-contact-block {
  display: flex;
  align-items: center;
  gap: var(--space-1);
  color: var(--color-neutral-white);
}

.contact-icon {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background-color: var(--color-primary-red);
  position: relative;
}

/* Simple geometric phone icon */
.contact-icon-phone::before,
.contact-icon-phone::after {
  content: "";
  position: absolute;
  background-color: var(--color-neutral-white);
}

.contact-icon-phone::before {
  width: 14px;
  height: 14px;
  border-radius: 3px;
  left: 9px;
  top: 9px;
}

.contact-icon-phone::after {
  width: 8px;
  height: 3px;
  border-radius: 2px;
  left: 12px;
  top: 20px;
}

/* Simple location pin */
.contact-icon-location::before,
.contact-icon-location::after {
  content: "";
  position: absolute;
}

.contact-icon-location::before {
  width: 16px;
  height: 20px;
  border-radius: 10px;
  border: 3px solid var(--color-neutral-white);
  left: 8px;
  top: 5px;
  box-sizing: border-box;
}

.contact-icon-location::after {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background-color: var(--color-neutral-white);
  left: 13px;
  top: 10px;
}

.contact-text {
  display: flex;
  flex-direction: column;
}

.contact-label {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.16em;
  opacity: 0.7;
}

.contact-value {
  font-family: var(--font-heading);
  font-size: 16px;
  font-weight: var(--fw-semibold);
  margin-top: 2px;
}

.contact-value:hover,
.contact-value:focus {
  text-decoration: none;
  color: #ffffff;
}

/* Primary navigation bar ------------------------------ */

.primary-nav {
  background-color: var(--color-secondary-dark);
  border-bottom: 4px solid #1b1b1b;
}

.nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  align-items: stretch;
  justify-content: flex-start;
}

.nav-item {
  margin-right: var(--space-3);
}

.nav-link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 14px 0;
  color: var(--color-neutral-white);
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: var(--fw-medium);
  text-transform: uppercase;
  letter-spacing: 0.14em;
  border-top: 3px solid transparent;
}

.nav-link:hover,
.nav-link:focus {
  color: var(--color-primary-red);
  text-decoration: none;
}

.nav-link-active {
  color: var(--color-primary-red);
  border-top-color: var(--color-primary-red);
}

/* Footer --------------------------------------------- */

.site-footer {
  background-color: var(--color-primary-black);
  color: var(--color-secondary-light);
  flex-shrink: 0;
}

.footer-top {
  border-top: 4px solid var(--color-primary-red);
  padding: var(--space-4) 0 var(--space-3);
}

.footer-grid {
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1fr;
  gap: var(--space-3);
  align-items: flex-start;
}

.footer-column {
  font-size: var(--fs-small);
}

.footer-column-wide {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.footer-logo-mark {
  width: 40px;
  height: 40px;
  background: linear-gradient(135deg, var(--color-primary-red), #8f141a);
  position: relative;
}

.footer-logo-mark::before,
.footer-logo-mark::after {
  content: "";
  position: absolute;
  top: 7px;
  bottom: 7px;
  width: 5px;
  border-radius: 12px;
  background-color: var(--color-neutral-white);
}

.footer-logo-mark::before {
  left: 10px;
}

.footer-logo-mark::after {
  right: 10px;
}

.footer-logo-text {
  display: flex;
  flex-direction: column;
}

.footer-logo-name {
  font-family: var(--font-heading);
  font-size: 20px;
  letter-spacing: 0.3em;
  font-weight: var(--fw-medium);
}

.footer-logo-tagline {
  margin-top: 3px;
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  opacity: 0.75;
}

.footer-heading {
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: var(--fw-semibold);
  text-transform: uppercase;
  letter-spacing: 0.16em;
  margin: 0 0 var(--space-1);
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-links li + li {
  margin-top: 6px;
}

.footer-links a {
  color: var(--color-secondary-light);
  opacity: 0.85;
}

.footer-links a:hover,
.footer-links a:focus {
  opacity: 1;
  color: var(--color-primary-red);
  text-decoration: none;
}

.footer-bottom {
  border-top: 1px solid rgba(255, 255, 255, 0.08);
  padding: var(--space-2) 0;
}

.footer-bottom-inner {
  display: flex;
  align-items: center;
  justify-content: center;
}

.footer-copy {
  margin: 0;
  font-size: 11px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  opacity: 0.75;
}

/* Responsive adjustments ----------------------------- */

@media (max-width: 992px) {
  .brand-inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-3);
  }

  .brand-right {
    width: 100%;
    justify-content: flex-start;
    flex-wrap: wrap;
  }

  .nav-list {
    flex-wrap: wrap;
  }

  .nav-item {
    margin-right: var(--space-2);
  }
}

@media (max-width: 768px) {
  .utility-inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-1);
  }

  .brand-inner {
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
  }

  .logo-name {
    font-size: 22px;
    letter-spacing: 0.25em;
  }

  .primary-nav .container {
    padding-left: var(--space-2);
    padding-right: var(--space-2);
  }

  .nav-list {
    gap: var(--space-1);
  }

  .nav-link {
    font-size: 12px;
    letter-spacing: 0.12em;
    padding: 10px 0;
  }

  .footer-grid {
    grid-template-columns: 1fr 1fr;
  }

  .footer-column-wide {
    grid-column: 1 / -1;
  }
}

@media (max-width: 520px) {
  .utility-bar {
    height: auto;
  }

  .utility-left {
    flex-wrap: wrap;
  }

  .brand-right {
    flex-direction: column;
    align-items: flex-start;
  }

  .footer-grid {
    grid-template-columns: 1fr;
  }
}
